create table if not exists teams(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations on delete cascade,name text not null,slug text not null,created_at timestamptz not null default now(),unique(organization_id,slug));
create table if not exists team_members(team_id uuid references teams on delete cascade,user_id uuid references users on delete cascade,role text not null default 'member',primary key(team_id,user_id));
create table if not exists api_tokens(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations on delete cascade,user_id uuid references users on delete set null,name text not null,token_hash text not null unique,last_four text not null,scopes text[] not null default '{}',expires_at timestamptz,last_used_at timestamptz,revoked_at timestamptz,created_at timestamptz not null default now());
create table if not exists policies(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations on delete cascade,name text not null,effect text not null check(effect in ('allow','deny')),action text not null,resource text not null,conditions jsonb not null default '{}'::jsonb,enabled boolean not null default true,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists compliance_controls(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations on delete cascade,framework text not null,control_key text not null,title text not null,status text not null check(status in ('passing','failing','unknown')),evidence jsonb not null default '[]'::jsonb,updated_at timestamptz not null default now(),unique(organization_id,framework,control_key));
create index if not exists api_tokens_org_idx on api_tokens(organization_id) where revoked_at is null;create index if not exists policies_org_idx on policies(organization_id,enabled);create index if not exists compliance_org_idx on compliance_controls(organization_id,framework);
